import type { ThreeEvent } from "@react-three/fiber";
import { useMemo } from "react";
import * as ClipperLib from "clipper-lib";
import { getStrokePoints } from "perfect-freehand";
import * as THREE from "three";
import { getPointBounds, layerToZ } from "../../../lib/sceneMath";
import type { Point2D, Stroke } from "../../../types/editor";
import {
  ResizeHandleMarker,
  RotationHandleMarker,
  SelectionFrame,
} from "./SelectionVisuals";

const clipperScale = 100;
const strokeSmoothingOptions = {
  thinning: 0,
  smoothing: 0.46,
  streamline: 0.18,
  simulatePressure: true,
  last: true,
  start: { cap: true, taper: 0 },
  end: { cap: true, taper: 0 },
} as const;

function createShapeGeometryFromPaths(paths: ClipperLib.Paths) {
  const validPaths = paths.filter((path) => path.length >= 3);
  const outerPaths = validPaths.filter((path) =>
    ClipperLib.Clipper.Orientation(path),
  );
  const holePaths = validPaths.filter(
    (path) => !ClipperLib.Clipper.Orientation(path),
  );

  const shapes = outerPaths.map((path) => {
    const shape = new THREE.Shape();
    shape.moveTo(path[0].X / clipperScale, path[0].Y / clipperScale);

    for (let index = 1; index < path.length; index += 1) {
      shape.lineTo(path[index].X / clipperScale, path[index].Y / clipperScale);
    }
    shape.closePath();
    return { shape, path };
  });

  for (const holePath of holePaths) {
    const target = shapes.find(
      ({ path }) => ClipperLib.Clipper.PointInPolygon(holePath[0], path) !== 0,
    );
    if (!target) continue;

    const hole = new THREE.Path();
    hole.moveTo(holePath[0].X / clipperScale, holePath[0].Y / clipperScale);

    for (let index = 1; index < holePath.length; index += 1) {
      hole.lineTo(
        holePath[index].X / clipperScale,
        holePath[index].Y / clipperScale,
      );
    }
    hole.closePath();
    target.shape.holes.push(hole);
  }

  if (shapes.length === 0) return null;

  const geometry = new THREE.ShapeGeometry(shapes.map(({ shape }) => shape));
  geometry.computeVertexNormals();
  geometry.computeBoundingSphere();
  return geometry;
}

function getUsableStrokePoints(points: Point2D[]) {
  return points.filter((point, index) => {
    const previous = points[index - 1];
    if (!previous) return true;
    return Math.hypot(point.x - previous.x, point.y - previous.y) > 0.001;
  });
}

function getPerfectFreehandCenterPoints(points: Point2D[], radius: number) {
  const usablePoints = getUsableStrokePoints(points);
  if (usablePoints.length < 2) return null;

  const strokePoints = getStrokePoints(
    usablePoints.map((point) => [point.x, point.y]),
    {
      ...strokeSmoothingOptions,
      size: radius * 2,
    },
  );

  const centerPoints = strokePoints.map(({ point }) => ({
    x: point[0],
    y: point[1],
  }));
  return centerPoints.length >= 2 ? centerPoints : null;
}

function createStrokeRibbonGeometry(
  points: Point2D[],
  radius: number,
  jointSegments = 6,
) {
  const vertices: number[] = [];
  const indices: number[] = [];

  for (let index = 0; index < points.length - 1; index += 1) {
    const current = points[index];
    const next = points[index + 1];
    const dx = next.x - current.x;
    const dy = next.y - current.y;
    const length = Math.hypot(dx, dy);
    if (length < 0.001) continue;

    const normalX = -dy / length;
    const normalY = dx / length;
    const base = vertices.length / 3;
    vertices.push(
      current.x + normalX * radius,
      current.y + normalY * radius,
      0,
      current.x - normalX * radius,
      current.y - normalY * radius,
      0,
      next.x + normalX * radius,
      next.y + normalY * radius,
      0,
      next.x - normalX * radius,
      next.y - normalY * radius,
      0,
    );
    indices.push(base, base + 1, base + 2, base + 1, base + 3, base + 2);
  }

  for (const [index, point] of points.entries()) {
    const isEndpoint = index === 0 || index === points.length - 1;
    const segments = isEndpoint ? jointSegments + 2 : jointSegments;
    const base = vertices.length / 3;
    vertices.push(point.x, point.y, 0);

    for (let segment = 0; segment <= segments; segment += 1) {
      const angle = (segment / segments) * Math.PI * 2;
      vertices.push(
        point.x + Math.cos(angle) * radius,
        point.y + Math.sin(angle) * radius,
        0,
      );
    }

    for (let segment = 0; segment < segments; segment += 1) {
      indices.push(base, base + segment + 1, base + segment + 2);
    }
  }

  if (vertices.length === 0 || indices.length === 0) return null;

  const geometry = new THREE.BufferGeometry();
  geometry.setAttribute(
    "position",
    new THREE.Float32BufferAttribute(vertices, 3),
  );
  geometry.setIndex(indices);
  geometry.computeVertexNormals();
  geometry.computeBoundingSphere();
  return geometry;
}

function createRoundedStrokeGeometryFromCenterPoints(
  centerPoints: Point2D[],
  radius: number,
) {
  const path = centerPoints.map((point) => ({
    X: Math.round(point.x * clipperScale),
    Y: Math.round(point.y * clipperScale),
  }));
  const offset = new ClipperLib.ClipperOffset(
    2,
    Math.max(1, radius * clipperScale * 0.08),
  );
  const solution: ClipperLib.Paths = [];

  offset.AddPath(
    path,
    ClipperLib.JoinType.jtRound,
    ClipperLib.EndType.etOpenRound,
  );
  offset.Execute(solution, radius * clipperScale);

  const cleaned = ClipperLib.Clipper.CleanPolygons(
    solution,
    Math.max(1, clipperScale * 0.02),
  );

  return (
    createShapeGeometryFromPaths(cleaned) ??
    createStrokeRibbonGeometry(centerPoints, radius, 8)
  );
}

type StrokeMeshProperties = {
  stroke: Stroke;
  renderVisual: boolean;
  activelyDrawing: boolean;
  hitTestEnabled: boolean;
  selected: boolean;
  groupSelected: boolean;
  canMove: boolean;
  canResize: boolean;
  onSelect: (event: ThreeEvent<PointerEvent>) => void;
  onMoveStart: (point: Point2D) => void;
};

export function StrokeMesh({
  stroke,
  renderVisual,
  activelyDrawing,
  hitTestEnabled,
  selected,
  groupSelected,
  canMove,
  canResize,
  onSelect,
  onMoveStart,
}: StrokeMeshProperties) {
  const strokeSceneName = `stroke:${stroke.id}`;
  const bounds = useMemo(() => getPointBounds(stroke.points), [stroke.points]);
  const localPoints = useMemo(
    () =>
      stroke.points.map((point) => ({
        x: point.x - bounds.centerX,
        y: point.y - bounds.centerY,
      })),
    [bounds.centerX, bounds.centerY, stroke.points],
  );
  const geometry = useMemo(() => {
    if (localPoints.length < 2) return null;
    const centerPoints = getPerfectFreehandCenterPoints(
      localPoints,
      stroke.size,
    );
    if (!centerPoints) return null;

    const pickerRadius = Math.max(stroke.size * 1.45, stroke.size + 1.8);
    const visual = createRoundedStrokeGeometryFromCenterPoints(
      centerPoints,
      stroke.size,
    );
    if (!visual) return null;
    const continuity = createStrokeRibbonGeometry(
      centerPoints,
      Math.max(stroke.size * 0.62, stroke.size - 1.4),
      5,
    );

    return {
      visual,
      continuity,
      picker: hitTestEnabled
        ? createRoundedStrokeGeometryFromCenterPoints(
            centerPoints,
            pickerRadius,
          )
        : null,
    };
  }, [activelyDrawing, hitTestEnabled, localPoints, stroke.size]);

  return (
    <group
      name={strokeSceneName}
      position={[bounds.centerX, bounds.centerY, layerToZ(stroke.layer)]}
      rotation={[0, 0, THREE.MathUtils.degToRad(stroke.rotation ?? 0)]}
    >
      {geometry ? (
        <>
          {geometry.picker ? (
            <mesh
              name={`${strokeSceneName}:picker`}
              geometry={geometry.picker}
              renderOrder={stroke.layer * 10 + 2}
              onPointerDown={onSelect}
              userData={{
                sceneType: "stroke",
                sceneId: stroke.id,
                sceneLayer: stroke.layer,
                sceneName: strokeSceneName,
              }}
            >
              <meshBasicMaterial
                transparent
                opacity={0}
                depthTest={false}
                depthWrite={false}
              />
            </mesh>
          ) : null}
          {renderVisual ? (
            <>
              {geometry.continuity ? (
                <mesh
                  name={`${strokeSceneName}:continuity`}
                  geometry={geometry.continuity}
                  renderOrder={stroke.layer * 10}
                  raycast={() => null}
                >
                  <meshBasicMaterial
                    color={stroke.color}
                    transparent
                    opacity={1}
                    depthTest={false}
                    depthWrite={false}
                    side={THREE.DoubleSide}
                  />
                </mesh>
              ) : null}
              <mesh
                name={`${strokeSceneName}:visual`}
                geometry={geometry.visual}
                renderOrder={stroke.layer * 10 + 1}
                onPointerDown={onSelect}
                userData={{
                  sceneType: "stroke",
                  sceneId: stroke.id,
                  sceneLayer: stroke.layer,
                  sceneName: strokeSceneName,
                }}
              >
                <meshBasicMaterial
                  color={stroke.color}
                  transparent
                  opacity={1}
                  depthTest={false}
                  depthWrite={false}
                  side={THREE.DoubleSide}
                />
              </mesh>
            </>
          ) : null}
        </>
      ) : null}
      {selected || groupSelected ? (
        <group name={`${strokeSceneName}:selection`} position={[0, 0, 0.04]}>
          <SelectionFrame
            name={`${strokeSceneName}:selection-frame`}
            width={bounds.width}
            height={bounds.height}
            padding={46}
          />
          {selected && canResize ? (
            <>
              <ResizeHandleMarker
                name={`${strokeSceneName}:resize-handle:se`}
                width={bounds.width}
                height={bounds.height}
                offset={23}
                handleSize={8}
              />
              <RotationHandleMarker
                name={`${strokeSceneName}:rotation-handle`}
                height={bounds.height}
                offset={23}
                distance={30}
              />
            </>
          ) : null}
        </group>
      ) : null}
    </group>
  );
}

import { Html } from "@react-three/drei";
import { useThree } from "@react-three/fiber";
import { useCallback, useEffect, useMemo, useRef, useState } from "react";
import type { FocusEvent, KeyboardEvent } from "react";
import * as THREE from "three";
import { getEditorTextFontFamily } from "../../../lib/editorTextFonts";
import {
  DEFAULT_TEXT_FONT_SIZE,
  measureTextObject,
} from "../../../lib/objectTexture";
import { layerToZ } from "../../../lib/sceneMath";
import type { WebGLObject } from "../../../types/editor";

type TextEditOverlayProperties = {
  object: WebGLObject;
  value: string;
  onChange: (value: string) => void;
  onKeyDown: (event: KeyboardEvent<HTMLTextAreaElement>) => void;
  onBlur: (event: FocusEvent<HTMLTextAreaElement>) => void;
};

export function TextEditOverlay({
  object,
  value,
  onChange,
  onKeyDown,
  onBlur,
}: TextEditOverlayProperties) {
  const { camera, size } = useThree();
  const textareaReference = useRef<HTMLTextAreaElement>(null);
  const scrollContainerReference = useRef<HTMLElement | null>(null);
  const scrollPositionReference = useRef({ left: 0, top: 0 });
  const [draftValue, setDraftValue] = useState(value);
  const overlayName = `text-edit-overlay:${object.id}`;
  const pixelScale =
    camera instanceof THREE.OrthographicCamera
      ? Math.min(
          size.width /
            (Math.abs(camera.right - camera.left) /
              Math.max(camera.zoom, 0.001)),
          size.height /
            (Math.abs(camera.top - camera.bottom) /
              Math.max(camera.zoom, 0.001)),
        )
      : 1;
  const fontSize = object.fontSize ?? DEFAULT_TEXT_FONT_SIZE;
  const fontFamily = getEditorTextFontFamily(object.fontFamily);
  const measured = useMemo(
    () => measureTextObject(draftValue, fontSize, object.fontFamily),
    [draftValue, fontSize, object.fontFamily],
  );
  const maxOverlayWidth = Math.max(96, size.width - 24);
  const maxOverlayHeight = Math.max(
    fontSize * 1.55 * pixelScale,
    size.height - 24,
  );
  const overlayWidth = Math.min(
    maxOverlayWidth,
    Math.max(96, object.width * pixelScale, measured.width * pixelScale),
  );
  const overlayHeight = Math.min(
    maxOverlayHeight,
    Math.max(
      fontSize * 1.55 * pixelScale,
      object.height * pixelScale,
      measured.height * pixelScale,
    ),
  );
  const overlayFontSize = fontSize * pixelScale;
  const overlayLineHeight = fontSize * 1.22 * pixelScale;

  const captureScrollPosition = useCallback(() => {
    const textarea = textareaReference.current;
    const scrollContainer = textarea?.closest<HTMLElement>(
      ".stage-canvas-frame",
    );
    if (!scrollContainer) return;

    scrollContainerReference.current = scrollContainer;
    scrollPositionReference.current = {
      left: scrollContainer.scrollLeft,
      top: scrollContainer.scrollTop,
    };
  }, []);

  const restoreScrollPosition = useCallback(() => {
    const scrollContainer = scrollContainerReference.current;
    if (!scrollContainer) return;

    scrollContainer.scrollLeft = scrollPositionReference.current.left;
    scrollContainer.scrollTop = scrollPositionReference.current.top;
  }, []);

  const restoreScrollAfterBrowserFocus = useCallback(() => {
    restoreScrollPosition();
    requestAnimationFrame(restoreScrollPosition);
  }, [restoreScrollPosition]);

  const focusTextarea = useCallback(() => {
    const textarea = textareaReference.current;
    if (!textarea) return;
    captureScrollPosition();
    textarea.focus({ preventScroll: true });
    textarea.setSelectionRange(textarea.value.length, textarea.value.length);
    restoreScrollAfterBrowserFocus();
  }, [captureScrollPosition, restoreScrollAfterBrowserFocus]);

  useEffect(() => {
    focusTextarea();
    const animationFrame = requestAnimationFrame(focusTextarea);
    const fallbackTimer = window.setTimeout(focusTextarea, 80);

    return () => {
      cancelAnimationFrame(animationFrame);
      window.clearTimeout(fallbackTimer);
    };
  }, [focusTextarea]);

  return (
    <Html
      name={overlayName}
      position={[object.x, object.y, layerToZ(object.layer) + 0.08]}
      center
      occlude={false}
      zIndexRange={[1_000_000, 0]}
      wrapperClass="text-edit-html"
      style={{ pointerEvents: "auto", zIndex: 2_147_483_647 }}
    >
      <div
        className="text-edit-overlay-wrap"
        style={{ transform: `rotate(${object.rotation ?? 0}deg)` }}
      >
        <textarea
          ref={textareaReference}
          className="text-edit-overlay"
          data-scene-name={overlayName}
          style={{
            width: `${overlayWidth}px`,
            height: `${overlayHeight}px`,
            color: "transparent",
            WebkitTextFillColor: "transparent",
            fontFamily,
            fontSize: `${overlayFontSize}px`,
            lineHeight: `${overlayLineHeight}px`,
          }}
          defaultValue={value}
          autoFocus
          spellCheck={false}
          wrap="off"
          aria-label="텍스트 입력"
          onCompositionEnd={(event) => {
            const { value } = event.currentTarget;
            setDraftValue(value);
            onChange(value);
            restoreScrollAfterBrowserFocus();
          }}
          onInput={(event) => {
            const { value } = event.currentTarget;
            setDraftValue(value);
            onChange(value);
            restoreScrollAfterBrowserFocus();
          }}
          onKeyDown={onKeyDown}
          onPointerDown={(event) => event.stopPropagation()}
          onFocus={focusTextarea}
          onBlur={onBlur}
        />
      </div>
    </Html>
  );
}

