export const DEFAULT_TEXT_FONT_FAMILY = EDITOR_TEXT_FONT_PRESETS[0].id;

export function getEditorTextFontPreset(fontFamily = DEFAULT_TEXT_FONT_FAMILY) {
  return (
    EDITOR_TEXT_FONT_PRESETS.find((preset) => preset.id === fontFamily) ??
    EDITOR_TEXT_FONT_PRESETS[0]
  );
}

export function getEditorTextFontFamily(fontFamily = DEFAULT_TEXT_FONT_FAMILY) {
  return getEditorTextFontPreset(fontFamily).family;
}

export function getEditorTextCanvasFont(
  fontSize: number,
  fontFamily = DEFAULT_TEXT_FONT_FAMILY,
  fontWeight = EDITOR_TEXT_FONT_WEIGHT,
) {
  return `${fontWeight} ${fontSize}px ${getEditorTextFontFamily(fontFamily)}`;
}

export function getEditorTextTroikaFontUrl(
  fontFamily = DEFAULT_TEXT_FONT_FAMILY,
) {
  return (
    getEditorTextFontPreset(fontFamily).troikaFontUrl ??
    DEFAULT_TEXT_TROIKA_FONT_URL
  );
}

function getFontLoadFamilyValue(fontFamily: string) {
  if (
    fontFamily.includes(",") ||
    fontFamily.startsWith('"') ||
    fontFamily.startsWith("'")
  ) {
    return fontFamily;
  }

  return `"${fontFamily.replaceAll('"', '\\"')}"`;
}

export async function loadEditorTextFont(
  fontFamily = DEFAULT_TEXT_FONT_FAMILY,
) {
  if (typeof document === "undefined" || !document.fonts) return;

  const preset = getEditorTextFontPreset(fontFamily);
  const loadFamily = preset.loadFamily ?? preset.family;
  await document.fonts.load(
    `${EDITOR_TEXT_FONT_WEIGHT} 32px ${getFontLoadFamilyValue(loadFamily)}`,
    EDITOR_TEXT_FONT_LOAD_SAMPLE,
  );
}

export async function preloadEditorTextFonts() {
  if (typeof document === "undefined" || !document.fonts) return;

  await Promise.all(
    EDITOR_TEXT_FONT_PRESETS.map((preset) =>
      loadEditorTextFont(preset.id).catch(() => {}),
    ),
  );
  await document.fonts.ready;
}

import type { Stroke, WebGLObject } from "../types/editor";

export type PageExportState = {
  strokes: Stroke[];
  objects: WebGLObject[];
};

export type PageExportSource = {
  pageElement: HTMLElement;
  webglCanvas: HTMLCanvasElement;
  width: number;
  height: number;
  pageZoom?: number;
  stagePageScale?: number;
  editorState?: PageExportState;
};

export type ExportPageImageOptions = PageExportSource & {
  filename?: string;
};

export type PageExportMethod =
  | "current-foreign-object"
  | "modern-screenshot"
  | "playwright-screenshot";

export type PageExportResult = {
  method: PageExportMethod;
  canvas: HTMLCanvasElement;
  blob: Blob;
  width: number;
  height: number;
  durationMs: number;
};

export function loadImage(source: string) {
  return new Promise<HTMLImageElement>((resolve, reject) => {
    const image = new Image();
    image.addEventListener("load", () => resolve(image));
    image.onerror = () =>
      reject(new Error("Failed to load export image source."));
    image.src = source;
  });
}

export function canvasToBlob(canvas: HTMLCanvasElement) {
  return new Promise<Blob>((resolve, reject) => {
    canvas.toBlob((blob) => {
      if (!blob) {
        reject(new Error("Failed to create export image blob."));
        return;
      }
      resolve(blob);
    }, "image/png");
  });
}

function copyInputState(source: HTMLElement, clone: HTMLElement) {
  if (source instanceof HTMLInputElement && clone instanceof HTMLInputElement) {
    clone.value = source.value;
    if (source.checked) clone.setAttribute("checked", "");
  }

  if (
    source instanceof HTMLTextAreaElement &&
    clone instanceof HTMLTextAreaElement
  ) {
    clone.value = source.value;
    clone.textContent = source.value;
  }
}

function inlineComputedStyles(source: HTMLElement, clone: HTMLElement) {
  const computed = window.getComputedStyle(source);
  for (const property of computed) {
    clone.style.setProperty(
      property,
      computed.getPropertyValue(property),
      computed.getPropertyPriority(property),
    );
  }

  copyInputState(source, clone);

  const sourceChildren = [...source.children].filter(
    (child): child is HTMLElement => child instanceof HTMLElement,
  );
  const cloneChildren = [...clone.children].filter(
    (child): child is HTMLElement => child instanceof HTMLElement,
  );

  for (const [index, child] of sourceChildren.entries()) {
    const cloneChild = cloneChildren[index];
    if (!cloneChild) continue;
    inlineComputedStyles(child, cloneChild);
  }
}

export async function blobToDataUrl(blob: Blob) {
  return new Promise<string>((resolve, reject) => {
    const reader = new FileReader();
    reader.addEventListener("load", () => resolve(String(reader.result)));
    reader.onerror = () => reject(new Error("Failed to read image blob."));
    reader.readAsDataURL(blob);
  });
}

async function resolveExportImageSource(imageSource?: string) {
  if (!imageSource || imageSource.startsWith("data:")) {
    return imageSource;
  }

  if (!imageSource.startsWith("blob:")) {
    return imageSource;
  }

  const response = await fetch(imageSource);
  const blob = await response.blob();
  return blobToDataUrl(blob);
}

export async function createSerializablePageExportState(
  state: PageExportState,
): Promise<PageExportState> {
  return {
    strokes: state.strokes.map((stroke) => ({
      ...stroke,
      points: stroke.points.map((point) => ({ ...point })),
    })),
    objects: await Promise.all(
      state.objects.map(async (object) => ({
        ...object,
        imageSrc: await resolveExportImageSource(object.imageSrc),
      })),
    ),
  };
}

async function inlineImages(clone: HTMLElement) {
  const images = [...clone.querySelectorAll("img")];

  await Promise.all(
    images.map(async (image) => {
      const source = image.getAttribute("src");
      if (!source || source.startsWith("data:")) return;

      try {
        const response = await fetch(source);
        const blob = await response.blob();
        image.setAttribute("src", await blobToDataUrl(blob));
      } catch {
        // Keep the original src if the browser cannot inline it.
      }
    }),
  );
}

function waitForFrame() {
  return new Promise<void>((resolve) => {
    requestAnimationFrame(() => resolve());
  });
}

export async function createUnscaledMeasuredClone(
  element: HTMLElement,
  width: number,
  height: number,
) {
  const measurementFrame = document.createElement("div");
  measurementFrame.className = "stage-canvas-frame is-fixed-page";
  measurementFrame.style.position = "fixed";
  measurementFrame.style.left = "-100000px";
  measurementFrame.style.right = "auto";
  measurementFrame.style.top = "0";
  measurementFrame.style.bottom = "auto";
  measurementFrame.style.width = `${width}px`;
  measurementFrame.style.height = `${height}px`;
  measurementFrame.style.overflow = "hidden";
  measurementFrame.style.pointerEvents = "none";
  measurementFrame.style.setProperty("--exam-aspect", String(width / height));
  measurementFrame.style.setProperty("--stage-page-width", `${width}px`);
  measurementFrame.style.setProperty("--stage-page-height", `${height}px`);
  measurementFrame.style.setProperty("--stage-page-scale", "1");

  const measurementShell = document.createElement("div");
  measurementShell.className = "stage-page-scale-box";
  const measurementCanvasShell = document.createElement("div");
  measurementCanvasShell.className = "stage-canvas-shell";
  const measurementLayer = document.createElement("div");
  measurementLayer.className = "stage-react-exam-layer";
  const measurementPage = element.cloneNode(true) as HTMLElement;

  measurementLayer.append(measurementPage);
  measurementCanvasShell.append(measurementLayer);
  measurementShell.append(measurementCanvasShell);
  measurementFrame.append(measurementShell);
  document.body.append(measurementFrame);

  await waitForFrame();

  return {
    measuredElement: measurementPage,
    dispose: () => measurementFrame.remove(),
  };
}

export async function renderElementToImage(
  element: HTMLElement,
  width: number,
  height: number,
) {
  const measured = await createUnscaledMeasuredClone(element, width, height);

  try {
    const clone = measured.measuredElement.cloneNode(true) as HTMLElement;
    clone.setAttribute("xmlns", "http://www.w3.org/1999/xhtml");
    inlineComputedStyles(measured.measuredElement, clone);
    await inlineImages(clone);

    clone.style.width = `${width}px`;
    clone.style.height = `${height}px`;
    clone.style.setProperty("zoom", "1");
    clone.style.transform = "none";
    clone.style.transformOrigin = "top left";

    const markup = new XMLSerializer().serializeToString(clone);
    const svg = [
      `<svg xmlns="http://www.w3.org/2000/svg" width="${width}" height="${height}" viewBox="0 0 ${width} ${height}">`,
      `<foreignObject x="0" y="0" width="${width}" height="${height}">`,
      markup,
      "</foreignObject>",
      "</svg>",
    ].join("");

    return loadImage(
      `data:image/svg+xml;charset=utf-8,${encodeURIComponent(svg)}`,
    );
  } finally {
    measured.dispose();
  }
}

export function downloadBlob(blob: Blob, filename: string) {
  const url = URL.createObjectURL(blob);
  const link = document.createElement("a");
  link.href = url;
  link.download = filename;
  document.body.append(link);
  link.click();
  link.remove();
  window.setTimeout(() => URL.revokeObjectURL(url), 1000);
}

export async function createCurrentPageExportCanvas({
  pageElement,
  webglCanvas,
  width,
  height,
}: PageExportSource) {
  const exportCanvas = document.createElement("canvas");
  exportCanvas.width = width;
  exportCanvas.height = height;
  const context = exportCanvas.getContext("2d");
  if (!context) {
    throw new Error("Failed to create export canvas context.");
  }

  context.fillStyle = "#ffffff";
  context.fillRect(0, 0, width, height);

  const pageImage = await renderElementToImage(pageElement, width, height);
  context.drawImage(pageImage, 0, 0, width, height);

  const webglImage = await loadImage(webglCanvas.toDataURL("image/png"));
  context.drawImage(webglImage, 0, 0, width, height);

  return exportCanvas;
}

export async function createCurrentPageExportBlob(options: PageExportSource) {
  const canvas = await createCurrentPageExportCanvas(options);
  return canvasToBlob(canvas);
}

export async function createCurrentPageExportResult(
  options: PageExportSource,
): Promise<PageExportResult> {
  const startedAt = performance.now();
  const canvas = await createCurrentPageExportCanvas(options);
  const blob = await canvasToBlob(canvas);

  return {
    method: "current-foreign-object",
    canvas,
    blob,
    width: options.width,
    height: options.height,
    durationMs: performance.now() - startedAt,
  };
}

export async function exportPageImage({
  filename = "exam-with-handwriting.png",
  ...source
}: ExportPageImageOptions) {
  const result = await createCurrentPageExportResult(source);
  downloadBlob(result.blob, filename);
  console.info(
    `Exported ${filename} (${result.width}x${result.height}) in ${result.durationMs.toFixed(1)}ms`,
  );
  return result;
}

import * as THREE from "three";
import {
  DEFAULT_TEXT_FONT_FAMILY,
  getEditorTextCanvasFont,
} from "./editorTextFonts";

export const DEFAULT_TEXT_FONT_SIZE = 32;
export const MIN_TEXT_FONT_SIZE = 7;
export const MAX_TEXT_FONT_SIZE = 180;
export const DEFAULT_TEXT_COLOR = "#1f2a44";

const textLineHeightRatio = 1.22;

function configureTexture(texture: THREE.Texture) {
  texture.colorSpace = THREE.SRGBColorSpace;
  texture.flipY = false;
  texture.magFilter = THREE.LinearFilter;
  texture.minFilter = THREE.LinearFilter;
  texture.generateMipmaps = false;
  texture.anisotropy = 4;
  return texture;
}

function getTextLines(text: string) {
  const lines = text.split(/\r?\n/);
  return lines.length > 0 ? lines : [""];
}

export function clampTextFontSize(fontSize: number) {
  return THREE.MathUtils.clamp(
    fontSize,
    MIN_TEXT_FONT_SIZE,
    MAX_TEXT_FONT_SIZE,
  );
}

export function measureTextObject(
  text: string,
  fontSize = DEFAULT_TEXT_FONT_SIZE,
  fontFamily = DEFAULT_TEXT_FONT_FAMILY,
) {
  const safeFontSize = clampTextFontSize(fontSize);
  const lines = getTextLines(text || " ");
  const lineHeight = safeFontSize * textLineHeightRatio;
  const paddingX = Math.max(8, safeFontSize * 0.28);
  const paddingY = Math.max(4, safeFontSize * 0.14);

  if (typeof document === "undefined") {
    const maxLength = Math.max(1, ...lines.map((line) => line.length));
    return {
      width: Math.max(14, maxLength * safeFontSize * 0.62 + paddingX * 2),
      height: Math.max(lineHeight, lines.length * lineHeight + paddingY * 2),
    };
  }

  const canvas = document.createElement("canvas");
  const context = canvas.getContext("2d");
  if (!context) {
    return {
      width: Math.max(14, safeFontSize + paddingX * 2),
      height: Math.max(lineHeight, lines.length * lineHeight + paddingY * 2),
    };
  }

  context.font = getEditorTextCanvasFont(safeFontSize, fontFamily);
  const textWidth = Math.max(
    0,
    ...lines.map((line) => context.measureText(line || " ").width),
  );
  return {
    width: Math.max(14, Math.ceil(textWidth + paddingX * 2)),
    height: Math.max(
      lineHeight,
      Math.ceil(lines.length * lineHeight + paddingY * 2),
    ),
  };
}

type ImageTextureOptions = {
  imageSrc?: string;
  backgroundColor?: string;
};

function createPlaceholderTexture(backgroundColor = "#ffffff") {
  const canvas = document.createElement("canvas");
  canvas.width = 16;
  canvas.height = 16;
  const context = canvas.getContext("2d");
  if (context) {
    context.fillStyle = backgroundColor;
    context.fillRect(0, 0, canvas.width, canvas.height);
  }

  return configureTexture(new THREE.CanvasTexture(canvas));
}

export function createImageObjectTexture({
  imageSrc,
  backgroundColor,
}: ImageTextureOptions) {
  if (imageSrc) {
    if (!backgroundColor) {
      const texture = configureTexture(new THREE.Texture());
      const image = new Image();
      image.decoding = "async";
      if (/^https?:/i.test(imageSrc)) {
        image.crossOrigin = "anonymous";
      }

      image.addEventListener("load", () => {
        texture.image = image;
        texture.needsUpdate = true;
      });

      image.src = imageSrc;
      return texture;
    }

    const canvas = document.createElement("canvas");
    canvas.width = 16;
    canvas.height = 16;
    const texture = createPlaceholderTexture(backgroundColor);
    const image = new Image();
    image.decoding = "async";
    if (/^https?:/i.test(imageSrc)) {
      image.crossOrigin = "anonymous";
    }

    image.addEventListener("load", () => {
      canvas.width = image.naturalWidth || image.width;
      canvas.height = image.naturalHeight || image.height;
      const imageContext = canvas.getContext("2d");
      if (!imageContext) return;

      imageContext.fillStyle = backgroundColor;
      imageContext.fillRect(0, 0, canvas.width, canvas.height);
      imageContext.drawImage(image, 0, 0, canvas.width, canvas.height);
      texture.image = canvas;
      texture.needsUpdate = true;
    });

    image.src = imageSrc;
    return texture;
  }

  const canvas = document.createElement("canvas");
  canvas.width = 640;
  canvas.height = 420;
  const context = canvas.getContext("2d");

  if (context) {
    const gradient = context.createLinearGradient(
      0,
      0,
      canvas.width,
      canvas.height,
    );
    gradient.addColorStop(0, "#cbd7ff");
    gradient.addColorStop(1, "#c9f3e9");
    context.fillStyle = gradient;
    context.fillRect(0, 0, canvas.width, canvas.height);
    context.fillStyle = "rgba(255, 255, 255, 0.36)";
    for (let x = -canvas.height; x < canvas.width; x += 64) {
      context.fillRect(x, 0, 24, canvas.height);
    }
    context.fillStyle = "#17324d";
    context.font =
      "800 58px -apple-system, BlinkMacSystemFont, Segoe UI, sans-serif";
    context.textAlign = "center";
    context.textBaseline = "middle";
    context.fillText("Image", canvas.width / 2, canvas.height / 2);
  }

  const texture = new THREE.CanvasTexture(canvas);
  return configureTexture(texture);
}

import { domToPng } from "modern-screenshot";
import {
  canvasToBlob,
  createSerializablePageExportState,
  createUnscaledMeasuredClone,
  downloadBlob,
  loadImage,
  type PageExportResult,
  type PageExportSource,
} from "./exportPageImage";

export type PageExportMethodId = "modern-screenshot" | "playwright-screenshot";

export type PageExportAdapter = {
  id: PageExportMethodId;
  label: string;
  kind: "client" | "automation";
  export: (source: PageExportSource) => Promise<PageExportResult>;
};

export const modernScreenshotPageExportAdapter: PageExportAdapter = {
  id: "modern-screenshot",
  label: "modern-screenshot DOM exporter",
  kind: "client",
  export: async ({ pageElement, webglCanvas, width, height }) => {
    const startedAt = performance.now();
    const measured = await createUnscaledMeasuredClone(
      pageElement,
      width,
      height,
    );

    try {
      const pageDataUrl = await domToPng(measured.measuredElement, {
        width,
        height,
        scale: 1,
        backgroundColor: "#ffffff",
        style: {
          width: `${width}px`,
          height: `${height}px`,
          zoom: "1",
          transform: "none",
          transformOrigin: "top left",
        },
      });

      const exportCanvas = document.createElement("canvas");
      exportCanvas.width = width;
      exportCanvas.height = height;
      const context = exportCanvas.getContext("2d");
      if (!context) {
        throw new Error(
          "Failed to create modern-screenshot export canvas context.",
        );
      }

      context.fillStyle = "#ffffff";
      context.fillRect(0, 0, width, height);

      const pageImage = await loadImage(pageDataUrl);
      context.drawImage(pageImage, 0, 0, width, height);

      const webglImage = await loadImage(webglCanvas.toDataURL("image/png"));
      context.drawImage(webglImage, 0, 0, width, height);

      const blob = await canvasToBlob(exportCanvas);
      return {
        method: "modern-screenshot",
        canvas: exportCanvas,
        blob,
        width,
        height,
        durationMs: performance.now() - startedAt,
      };
    } finally {
      measured.dispose();
    }
  },
};

export const playwrightScreenshotPageExportAdapter: PageExportAdapter = {
  id: "playwright-screenshot",
  label: "Playwright headless browser element screenshot",
  kind: "automation",
  export: async ({ width, height, editorState }) => {
    const startedAt = performance.now();
    const serializableEditorState = editorState
      ? await createSerializablePageExportState(editorState)
      : undefined;
    const response = await fetch("/api/playwright-export", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        targetUrl: window.location.href,
        viewportWidth: 1600,
        viewportHeight: 1074,
        deviceScaleFactor: 1,
        editorState: serializableEditorState,
      }),
    });
    const payload = await response.json();

    if (!response.ok || !payload.ok) {
      throw new Error(payload.error ?? "Playwright screenshot export failed.");
    }

    const image = await loadImage(
      `data:${payload.image.mimeType};base64,${payload.image.base64}`,
    );
    const exportCanvas = document.createElement("canvas");
    exportCanvas.width = width;
    exportCanvas.height = height;
    const context = exportCanvas.getContext("2d");
    if (!context) {
      throw new Error(
        "Failed to create Playwright screenshot export canvas context.",
      );
    }

    context.fillStyle = "#ffffff";
    context.fillRect(0, 0, width, height);
    context.drawImage(image, 0, 0, width, height);

    const blob = await canvasToBlob(exportCanvas);
    return {
      method: "playwright-screenshot",
      canvas: exportCanvas,
      blob,
      width,
      height,
      durationMs: performance.now() - startedAt,
    };
  },
};

export const pageExportAdapters: PageExportAdapter[] = [
  modernScreenshotPageExportAdapter,
  playwrightScreenshotPageExportAdapter,
];

export async function downloadClientPageExportComparison(
  source: PageExportSource,
  filenamePrefix = "page-export-comparison",
) {
  const results: PageExportResult[] = [];

  for (const adapter of pageExportAdapters) {
    const result = await adapter.export(source);
    results.push(result);
    downloadBlob(result.blob, `${filenamePrefix}-${adapter.id}.png`);
  }

  console.table(
    results.map((result) => ({
      method: result.method,
      width: result.width,
      height: result.height,
      blobSize: result.blob.size,
      durationMs: Number(result.durationMs.toFixed(1)),
    })),
  );

  return results;
}

